import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { adminAPI } from '../../services/api';
import './AdminDashboard.css';

const AdminDashboard = () => {
  const { user, logout } = useAuth();
  const [stats, setStats] = useState({
    totalUsers: 0,
    totalMentors: 0,
    totalRequests: 0,
    pendingRequests: 0,
    acceptedRequests: 0
  });
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [message, setMessage] = useState({ type: '', text: '' });

  useEffect(() => {
    if (user && user.role === 'admin') {
      loadDashboardData();
    }
  }, [user]);

  const loadDashboardData = async () => {
    try {
      setLoading(true);
      const [statsResponse, requestsResponse] = await Promise.all([
        adminAPI.getDashboardStats(),
        adminAPI.getMentorshipRequests()
      ]);

      if (statsResponse.success) {
        setStats(statsResponse.stats);
      }

      if (requestsResponse.success) {
        setRequests(requestsResponse.requests);
      }

    } catch (error) {
      console.error('Error loading admin data:', error);
      setMessage({ type: 'error', text: 'Error loading dashboard data' });
    } finally {
      setLoading(false);
    }
  };

  const handleUpdateRequest = async (requestId, status, notes = '') => {
    try {
      const response = await adminAPI.updateMentorshipRequest(requestId, {
        status,
        adminNotes: notes
      });

      if (response.success) {
        setMessage({ type: 'success', text: `Request ${status} successfully` });
        loadDashboardData(); // Refresh data
      }
    } catch (error) {
      console.error('Error updating request:', error);
      setMessage({ type: 'error', text: 'Error updating request' });
    }
  };

  const getStatusBadge = (status) => {
    const statusConfig = {
      pending: { class: 'status-pending', text: '⏳ Pending' },
      accepted: { class: 'status-accepted', text: '✅ Accepted' },
      rejected: { class: 'status-rejected', text: '❌ Rejected' },
      completed: { class: 'status-completed', text: '🎉 Completed' }
    };
    
    const config = statusConfig[status] || statusConfig.pending;
    return <span className={`status-badge ${config.class}`}>{config.text}</span>;
  };

  if (!user || user.role !== 'admin') {
    return (
      <div className="admin-container">
        <div className="access-denied">
          <h2>🚫 Access Denied</h2>
          <p>Admin privileges required to access this page.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="admin-dashboard">
      {/* Header */}
      <div className="admin-header">
        <div className="admin-header-content">
          <h1>👨‍💼 Admin Dashboard</h1>
          <div className="admin-actions">
            <span>Welcome, {user.name}</span>
            <button onClick={logout} className="btn btn-logout">
              🚪 Logout
            </button>
          </div>
        </div>
      </div>

      {/* Navigation */}
      <div className="admin-nav">
        <button 
          className={`nav-btn ${activeTab === 'dashboard' ? 'active' : ''}`}
          onClick={() => setActiveTab('dashboard')}
        >
          📊 Dashboard
        </button>
        <button 
          className={`nav-btn ${activeTab === 'requests' ? 'active' : ''}`}
          onClick={() => setActiveTab('requests')}
        >
          📨 Mentorship Requests
          {stats.pendingRequests > 0 && (
            <span className="notification-badge">{stats.pendingRequests}</span>
          )}
        </button>
      </div>

      {/* Message */}
      {message.text && (
        <div className={`admin-message ${message.type}`}>
          {message.text}
        </div>
      )}

      {/* Loading */}
      {loading && (
        <div className="admin-loading">
          <div className="spinner"></div>
          <p>Loading admin data...</p>
        </div>
      )}

      {/* Dashboard Tab */}
      {activeTab === 'dashboard' && !loading && (
        <div className="dashboard-tab">
          <div className="stats-grid">
            <div className="stat-card">
              <div className="stat-icon">👥</div>
              <div className="stat-info">
                <h3>Total Users</h3>
                <span className="stat-number">{stats.totalUsers}</span>
              </div>
            </div>

            <div className="stat-card">
              <div className="stat-icon">👨‍🏫</div>
              <div className="stat-info">
                <h3>Active Mentors</h3>
                <span className="stat-number">{stats.totalMentors}</span>
              </div>
            </div>

            <div className="stat-card">
              <div className="stat-icon">📨</div>
              <div className="stat-info">
                <h3>Total Requests</h3>
                <span className="stat-number">{stats.totalRequests}</span>
              </div>
            </div>

            <div className="stat-card">
              <div className="stat-icon">⏳</div>
              <div className="stat-info">
                <h3>Pending Requests</h3>
                <span className="stat-number">{stats.pendingRequests}</span>
              </div>
            </div>
          </div>

          {/* Quick Actions */}
          <div className="quick-actions">
            <h3>🚀 Quick Actions</h3>
            <div className="action-buttons">
              <button 
                onClick={() => setActiveTab('requests')}
                className="btn btn-primary"
              >
                📨 Manage Requests
              </button>
              <button 
                onClick={loadDashboardData}
                className="btn btn-secondary"
              >
                🔄 Refresh Data
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Requests Tab */}
      {activeTab === 'requests' && !loading && (
        <div className="requests-tab">
          <div className="requests-header">
            <h2>📨 Mentorship Requests</h2>
            <div className="requests-stats">
              <span>Total: {stats.totalRequests}</span>
              <span className="pending-count">Pending: {stats.pendingRequests}</span>
            </div>
          </div>

          {requests.length === 0 ? (
            <div className="no-requests">
              <p>No mentorship requests found.</p>
            </div>
          ) : (
            <div className="requests-list">
              {requests.map((request) => (
                <div key={request._id} className="request-card">
                  <div className="request-header">
                    <div className="request-info">
                      <h4>{request.userName} → {request.mentorName}</h4>
                      <p className="request-meta">
                        📧 {request.userEmail} • 
                        📅 {new Date(request.requestedAt).toLocaleDateString()}
                      </p>
                    </div>
                    <div className="request-status">
                      {getStatusBadge(request.status)}
                    </div>
                  </div>

                  {request.adminNotes && (
                    <div className="admin-notes">
                      <strong>Admin Notes:</strong> {request.adminNotes}
                    </div>
                  )}

                  <div className="request-actions">
                    {request.status === 'pending' && (
                      <>
                        <button
                          onClick={() => handleUpdateRequest(request._id, 'accepted', 'Request accepted by admin')}
                          className="btn btn-success btn-small"
                        >
                          ✅ Accept
                        </button>
                        <button
                          onClick={() => handleUpdateRequest(request._id, 'rejected', 'Request rejected by admin')}
                          className="btn btn-danger btn-small"
                        >
                          ❌ Reject
                        </button>
                      </>
                    )}
                    
                    {request.status === 'accepted' && (
                      <button
                        onClick={() => handleUpdateRequest(request._id, 'completed', 'Mentorship completed')}
                        className="btn btn-primary btn-small"
                      >
                        🎉 Mark Complete
                      </button>
                    )}

                    <button
                      onClick={() => {
                        const notes = prompt('Add admin notes:', request.adminNotes || '');
                        if (notes !== null) {
                          handleUpdateRequest(request._id, request.status, notes);
                        }
                      }}
                      className="btn btn-secondary btn-small"
                    >
                      📝 Add Notes
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;
